  1→import type { ReactNode } from 'react';
  2→import { useCallback, useMemo } from 'react';
  3→import { TAG_COLOR_HEX } from '../../../constants/tag_colors';
  4→import type { ListItemAccessoryData } from '../../../types';
  5→import { formatRelativeDate } from '../../../utils/format_date';
  6→import { useListContext } from '../list_context';
  7→import './list_item.scss';
  8→
  9→export interface ListItemProps {
 10→  index: number;
 11→  icon?: ReactNode;
 12→  title: string;
 13→  subtitle?: string;
 14→  accessories?: ListItemAccessoryData[];
 15→  onClick?: () => void;
 16→}
 17→
 18→export function ListItem({
 19→  index,
 20→  icon,
 21→  title,
 22→  subtitle,
 23→  accessories,
 24→  onClick,
 25→}: ListItemProps) {
 26→  const { activeIndex, setActiveIndex } = useListContext();
 27→  const isActive = activeIndex === index;
 28→  const now = useMemo(() => new Date(), []);
 29→
 30→  const handleMouseEnter = useCallback(() => {
 31→    setActiveIndex(index);
 32→  }, [
 33→    index,
 34→    setActiveIndex,
 35→  ]);
 36→
 37→  return (
 38→    <div
 39→      id={`list-item-${index}`}
 40→      className={`list-item${isActive ? ' list-item--active' : ''}`}
 41→      data-list-index={index}
 42→      role="option"
 43→      aria-selected={isActive}
 44→      onMouseEnter={handleMouseEnter}
 45→      onClick={onClick}
 46→    >
 47→      <div className="list-item__left">
 48→        {icon && <span className="list-item__icon">{icon}</span>}
 49→        <span className="list-item__title">{title}</span>
 50→        {subtitle && <span className="list-item__subtitle">{subtitle}</span>}
 51→      </div>
 52→      {accessories && accessories.length > 0 && (
 53→        <div className="list-item__accessories">
 54→          {accessories.map((accessory, i) => {
 55→            if (accessory.tag) {
 56→              const hex = accessory.tag.color
 57→                ? TAG_COLOR_HEX[accessory.tag.color]
 58→                : undefined;
 59→              return (
 60→                <span
 61→                  key={i}
 62→                  className="list-item__accessory-tag"
 63→                  style={
 64→                    hex
 65→                      ? {
 66→                          color: hex,
 67→                          backgroundColor: `${hex}26`,
 68→                        }
 69→                      : undefined
 70→                  }
 71→                >
 72→                  {accessory.tag.text}
 73→                </span>
 74→              );
 75→            }
 76→            const displayText = accessory.date
 77→              ? formatRelativeDate(accessory.date, now)
 78→              : accessory.text;
 79→
 80→            return (
 81→              <span
 82→                key={i}
 83→                className="list-item__accessory"
 84→                title={
 85→                  accessory.date ? accessory.date.toLocaleString() : undefined
 86→                }
 87→              >
 88→                {accessory.icon}
 89→                {displayText && (
 90→                  <span className="list-item__accessory-text">
 91→                    {displayText}
 92→                  </span>
 93→                )}
 94→              </span>
 95→            );
 96→          })}
 97→        </div>
 98→      )}
 99→    </div>
100→  );
101→}
